// MARK: - Keychain Helper
class KeychainManager {
    
    static let shared = KeychainManager()
    private init() {}
    
    private let service = "com.myapp.authentication"
    private let account = "biometricAuthEnabled"
    private let authTokenAccount = "authToken"
    
    func setBiometricAuthEnabled(_ enabled: Bool) {
        let data = Data([enabled ? 1 : 0])
        save(data: data, forAccount: account)
    }
    
    func isBiometricAuthEnabled() -> Bool {
        guard let data = load(account: account), let firstByte = data.first else {
            return false
        }
        return firstByte == 1
    }
    
    func saveAuthToken(_ token: String) {
        guard let data = token.data(using: .utf8) else { return }
        save(data: data, forAccount: authTokenAccount)
    }
    
    func loadAuthToken() -> String? {
        guard let data = load(account: authTokenAccount) else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func clearAll() {
        delete(account: account)
        delete(account: authTokenAccount)
    }
    
    private func save(data: Data, forAccount account: String) {
        delete(account: account)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemAdd(query as CFDictionary, nil)
    }
    
    private func load(account: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
    
    private func delete(account: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Biometric Auth Manager
class BiometricAuthManager {
    
    static let shared = BiometricAuthManager()
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    enum AuthResult {
        case success
        case failure(Error)
        case biometryNotAvailable
        case biometryNotEnrolled
        case biometryLockout
        case userCancel
        case userFallback
    }
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .none
        @unknown default:
            return .none
        }
    }
    
    var biometricTypeString: String {
        switch biometricType {
        case .faceID:
            return "Face ID"
        case .touchID:
            return "Touch ID"
        case .none:
            return "Biometrics"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    func authenticate(reason: String? = nil, completion: @escaping (AuthResult) -> Void) {
        let context = LAContext()
        context.localizedFallbackTitle = "Enter Password"
        context.localizedCancelTitle = "Cancel"
        
        var error: NSError?
        let policy: LAPolicy = .deviceOwnerAuthenticationWithBiometrics
        
        guard context.canEvaluatePolicy(policy, error: &error) else {
            if let error = error {
                let result = mapLAError(error)
                DispatchQueue.main.async {
                    completion(result)
                }
            } else {
                DispatchQueue.main.async {
                    completion(.biometryNotAvailable)
                }
            }
            return
        }
        
        let authReason = reason ?? "Authenticate with \(biometricTypeString) to access your account"
        
        context.evaluatePolicy(policy, localizedReason: authReason) { success, error in
            DispatchQueue.main.async {
                if success {
                    completion(.success)
                } else if let error = error {
                    completion(self.mapLAError(error))
                } else {
                    completion(.failure(NSError(domain: "BiometricAuth", code: -1, userInfo: [NSLocalizedDescriptionKey: "Unknown error"])))
                }
            }
        }
    }
    
    private func mapLAError(_ error: Error) -> AuthResult {
        let nsError = error as NSError
        
        guard let laError = LAError.Code(rawValue: nsError.code) else {
            return .failure(error)
        }
        
        switch laError {
        case .biometryNotAvailable:
            return .biometryNotAvailable
        case .biometryNotEnrolled:
            return .biometryNotEnrolled
        case .biometryLockout:
            return .biometryLockout
        case .userCancel:
            return .userCancel
        case .userFallback:
            return .userFallback
        case .authenticationFailed:
            return .failure(error)
        default:
            return .failure(error)
        }
    }
}

