        }
        
        guard let password = passwordTextField.text, !password.isEmpty else {
            showError("Please enter your password")
            return
        }
        
        setLoading(true)
        
        let enableBiometric = enableBiometricSwitch.isOn && BiometricAuthManager.shared.isBiometricAvailable
        
        SessionManager.shared.loginWithCredentials(
            username: username,
            password: password,
            enableBiometric: enableBiometric
        ) { [weak self] success, errorMessage in
            self?.setLoading(false)
            
            if success {
                self?.navigateToHome()
            } else {
                self?.showError(errorMessage ?? "Login failed. Please try again.")
            }
        }
    }
    
    @objc private func biometricButtonTapped() {
        attemptBiometricLogin()
    }
    
    private func attemptBiometricLogin() {
        BiometricAuthManager.shared.authenticate { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success:
                if let _ = KeychainManager.shared.loadAuthToken() {
                    SessionManager.shared.loginWithBiometric { success in
                        if success {
                            self.navigateToHome()
                        } else {
                            self.showError("Session expired. Please sign in with your password.")
                        }
                    }
                }
                
            case .failure:
                self.showBiometricRetryAlert(message: "Authentication failed. Would you like to try again?")
                
            case .biometryLockout:
                self.showBiometricRetryAlert(message: "\(BiometricAuthManager.shared.biometricTypeString) is locked due to too many failed attempts. Please enter your password.")
                
            case .biometryNotAvailable:
                self.showError("\(BiometricAuthManager.shared.biometricTypeString) is not available on this device.")
                
            case .biometryNotEnrolled:
                self.showBiometricEnrollmentAlert()
                
            case .userCancel:
                // User cancelled — do nothing, let them enter password
                break
                
            case .userFallback:
                // User chose to enter password
                self.usernameTextField.becomeFirstResponder()
            }
        }
    }
    
    private func showBiometricRetryAlert(message: String) {
        let alert = UIAlertController(
            title: "Authentication Failed",
            message: message,
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Try Again", style: .default) { [weak self] _ in
            self?.attemptBiometricLogin()
        })
        
        alert.addAction(UIAlertAction(title: "Enter Password", style: .cancel) { [weak self] _ in
            self?.usernameTextField.becomeFirstResponder()
        })
        
        present(alert, animated: true)
    }
    
    private func showBiometricEnrollmentAlert() {
        let biometricName = BiometricAuthManager.shared.biometricTypeString
        
        let alert = UIAlertController(
            title: "\(biometricName) Not Set Up",
            message: "Please set up \(biometricName) in your device Settings to use this feature.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Open Settings", style: .default) { _ in
            if let url = URL(string: UIApplication.openSettingsURLString) {
                UIApplication.shared.open(url)
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func showError(_ message: String) {
        errorLabel.text = message
        errorLabel.isHidden = false
        
        // Shake animation
        let animation = CAKeyframeAnimation(keyPath: "transform.translation.x")
        animation.timingFunction = CAMediaTimingFunction(name: .linear)
        animation.duration = 0.4
        animation.values = [-10, 10, -8, 8, -5, 5, 0]
        errorLabel.layer.add(animation, forKey: "shake")
    }
    
    private func setLoading(_ loading: Bool) {
        loginButton.isEnabled = !loading
        usernameTextField.isEnabled = !loading
        passwordTextField.isEnabled = !loading
        biometricButton.isEnabled = !loading
        
        if loading {
            loginButton.setTitle("", for: .normal)
            activityIndicator.startAnimating()
        } else {
            loginButton.setTitle("Sign In", for: .normal)
            activityIndicator.stopAnimating()
        }
    }
    
    private func navigateToHome() {
        let homeVC = HomeViewController()
        homeVC.modalPresentationStyle = .fullScreen
        homeVC.modalTransitionStyle = .crossDissolve
        
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
                window.rootViewController = UINavigationController(rootViewController: homeVC)
            }
        }
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
}

