            logoutButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -32),
            logoutButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            logoutButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            logoutButton.heightAnchor.constraint(equalToConstant: 50),
        ])
    }
    
    private func updateBiometricStatus() {
        let biometricEnabled = KeychainManager.shared.isBiometricAuthEnabled()
        let biometricName = BiometricAuthManager.shared.biometricTypeString
        
        if biometricEnabled {
            biometricStatusLabel.text = "\(biometricName) login is enabled.\nYou'll be able to sign in quickly next time."
            disableBiometricButton.isHidden = false
        } else {
            biometricStatusLabel.text = "Biometric login is disabled."
            disableBiometricButton.isHidden = true
        }
    }
    
    @objc private func disableBiometricTapped() {
        let alert = UIAlertController(
            title: "Disable Biometric Login?",
            message: "You'll need to enter your password each time you sign in.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Disable", style: .destructive) { [weak self] _ in
            SessionManager.shared.disableBiometric()
            self?.updateBiometricStatus()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    @objc private func logoutTapped() {
        let alert = UIAlertController(
            title: "Sign Out",
            message: "Are you sure you want to sign out?",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Sign Out", style: .destructive) { _ in
            SessionManager.shared.logout()
            
            if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
               let window = windowScene.windows.first {
                UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
                    window.rootViewController = LoginViewController()
                }
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
}

// MARK: - App Delegate / Scene Delegate Integration
class AppFlowCoordinator {
    
    static let shared = AppFlowCoordinator()
    private init() {}
    
    func initialViewController() -> UIViewController {
        if SessionManager.shared.shouldAttemptBiometricAuth {
            // Show login screen but it will auto-trigger biometric
            return LoginViewController()
        } else if let _ = KeychainManager.shared.loadAuthToken() {
            // Has token but biometric not enabled - still need to verify
            return LoginViewController()
        } else {
            return LoginViewController()
        }
    }
    
    /// Call this from SceneDelegate's scene(_:willConnectTo:options:)
    func configureWindow(_ window: UIWindow) {
        let rootVC = initialViewController()
        
        if SessionManager.shared.shouldAttemptBiometricAuth {
            // Will auto-attempt biometric on viewDidAppear
            window.rootViewController = rootVC
        } else {
            window.rootViewController = rootVC
        }
        
        window.makeKeyAndVisible()
    }
}

// MARK: - SceneDelegate Example
class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        AppFlowCoordinator.shared.configureWindow(window)
        self.window = window
    }
    
    func sceneDidBecomeActive(_ scene: UIScene) {
        // Optional: Re-authenticate when app becomes active after background
    }
    
    func sceneWillResignActive(_ scene: UIScene) {
        // Optional: Add a privacy screen overlay
    }
}